import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Rule Authoring","description":"","frontmatter":{},"headers":[],"relativePath":"settings/rule-authoring.md","filePath":"settings/rule-authoring.md","lastUpdated":1782658073000}'),i={name:"settings/rule-authoring.md"};function r(l,e,n,d,c,h){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="rule-authoring" tabindex="-1">Rule Authoring <a class="header-anchor" href="#rule-authoring" aria-label="Permalink to &quot;Rule Authoring&quot;">​</a></h1><p>EasyApi understands standard HTTP frameworks (Spring MVC, WebFlux, JAX-RS, Feign) out of the box — <strong>most projects need no custom rules</strong>. For custom framework behaviour the scanner can&#39;t see (e.g. a <code>jakarta.servlet.Filter</code> that requires a header, or a <code>ResponseBodyAdvice</code> that wraps every response in an envelope), use the built-in AI Assistant or the external skill to detect it and generate the rule. See the <a href="https://github.com/tangcent/easy-yapi/blob/master/docs/knowledge-base/rule-guide.md" target="_blank" rel="noreferrer">Rule Authoring Guide</a> for the full Custom-Pattern Catalog.</p><p>This page introduces the <strong>three ways</strong> to author rules in EasyYapi 3.x. Pick the one that matches your workflow.</p><table tabindex="0"><thead><tr><th>Method</th><th>Best for</th><th>Where it lives</th></tr></thead><tbody><tr><td><a href="#folder-based-rule-files">Folder-based rule files</a></td><td>Teams that want plain-text rules under version control</td><td><code>.easyapi/*.rules</code></td></tr><tr><td><a href="#built-in-ai-assistant">Built-in AI Assistant</a></td><td>Quick one-offs, scanning a project for hidden framework behaviour</td><td>Settings → EasyApi → Rules → Chat / Magic</td></tr><tr><td><a href="#external-easy-yapi-assistant-skill">External <code>easy-yapi-assistant</code> skill</a></td><td>Driving rule authoring from an external AI tool (CLI / IDE agent)</td><td>bundled inside the plugin</td></tr></tbody></table><hr><h2 id="folder-based-rule-files" tabindex="-1">Folder-based rule files <a class="header-anchor" href="#folder-based-rule-files" aria-label="Permalink to &quot;Folder-based rule files&quot;">​</a></h2><p>Starting with EasyYapi 3.0, rule files are discovered by <strong>folder</strong>, replacing the legacy single <code>.easy.api.config</code> file workflow (legacy files are still read for backwards compatibility).</p><h3 id="where-rule-files-live" tabindex="-1">Where rule files live <a class="header-anchor" href="#where-rule-files-live" aria-label="Permalink to &quot;Where rule files live&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scope</th><th>Folder</th><th>Applies to</th></tr></thead><tbody><tr><td><strong>Project</strong></td><td><code>&lt;project&gt;/.easyapi/*.rules</code> (or <code>*.properties</code>)</td><td>The current project only</td></tr><tr><td><strong>Global</strong></td><td><code>~/.easyapi/*.rules</code></td><td>Every project on this machine</td></tr><tr><td><strong>Built-in</strong></td><td>bundled inside the plugin</td><td>Always loaded</td></tr><tr><td><strong>Remote</strong></td><td>URLs configured in Settings → Remote</td><td>Pulled on reload</td></tr></tbody></table><p>Every regular file in a folder is loaded automatically — there is no list to maintain. The folder is the source of truth.</p><h3 id="file-format" tabindex="-1">File format <a class="header-anchor" href="#file-format" aria-label="Permalink to &quot;File format&quot;">​</a></h3><p>A rule file is a UTF-8 text file with one rule per line:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Format: &lt;key&gt;[&lt;filter&gt;]=&lt;value&gt;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   key      — a rule key (see Available Config Rules)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   filter   — optional; goes INSIDE [...] AFTER the key</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#   value    — literal text, expression, or Groovy script</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># A rule with no filter applies to every element:</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">api.status</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=disabled</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># A rule with a filter applies only to matching elements:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api.tag[$class:com.example.UserController]=user</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Groovy scripts are prefixed with &quot;groovy:&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">field.ignore[groovy: it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;internalCache&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]=true</span></span></code></pre></div><h3 id="managing-files-inside-the-ide" tabindex="-1">Managing files inside the IDE <a class="header-anchor" href="#managing-files-inside-the-ide" aria-label="Permalink to &quot;Managing files inside the IDE&quot;">​</a></h3><p>Open <strong>Settings → EasyApi → Rules</strong>. The tab has three sub-tabs — <strong>Project</strong>, <strong>Global</strong>, <strong>Remote</strong>:</p><ul><li>Add / edit / rename / remove files directly from the dialog.</li><li>Uncheck the <strong>Enabled</strong> box next to a file to disable it without deleting it. Disabled paths are persisted in <code>Settings.disabledAutoRuleFiles</code> (project) or <code>Settings.disabledGlobalRuleFiles</code> (global).</li><li>Files are reloaded on save — no IDE restart needed.</li></ul><h3 id="filter-syntax-cheat-sheet" tabindex="-1">Filter syntax cheat sheet <a class="header-anchor" href="#filter-syntax-cheat-sheet" aria-label="Permalink to &quot;Filter syntax cheat sheet&quot;">​</a></h3><p>Filters appear <strong>inside <code>[...]</code> after the key</strong> and restrict the rule to matching elements:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>$class:</code></td><td>Exact fully-qualified class-name match</td><td><code>$class:com.example.UserController</code></td></tr><tr><td><code>@</code></td><td>Matches elements annotated with the given annotation</td><td><code>@org.springframework.web.bind.annotation.RestController</code></td></tr><tr><td><code>#regex:</code></td><td>Regex match; capture groups available as <code>\${1}</code>, <code>\${2}</code></td><td><code>#regex:Mono&lt;(.*?)&gt;</code></td></tr><tr><td><code>#</code></td><td>Tag match (from comments or annotations)</td><td><code>#internal</code></td></tr><tr><td><code>!</code></td><td>Negates the following expression</td><td><code>!@java.lang.Deprecated</code></td></tr><tr><td><code>groovy:</code></td><td>Truthy Groovy script</td><td><code>groovy: it.hasAnn(&quot;X&quot;)</code></td></tr><tr><td><em>(none)</em></td><td>Literal value, always matches</td><td><code>api.status=disabled</code></td></tr></tbody></table><blockquote><p><strong>Migration note:</strong> the 2.x <code>class:com.example.Foo</code> and <code>~regex</code> forms are invalid in 3.x. Use <code>$class:</code> (exact match) or <code>groovy:</code> (pattern match) instead. See <a href="./config-rule">Available Config Rules</a> for the full key catalog.</p></blockquote><hr><h2 id="built-in-ai-assistant" tabindex="-1">Built-in AI Assistant <a class="header-anchor" href="#built-in-ai-assistant" aria-label="Permalink to &quot;Built-in AI Assistant&quot;">​</a></h2><p>EasyYapi 3.0 ships a provider-neutral AI assistant that can author rules for you in natural language. It is wired into the Rules tab and reads the same knowledge base the external skill uses.</p><h3 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h3><ol><li>Open <strong>Settings → EasyApi → AI</strong> (a dedicated top-level tab).</li><li>Choose a provider (<code>OPENAI</code>, <code>ANTHROPIC</code>, <code>GEMINI</code>, <code>OLLAMA</code>, <code>AZURE_OPENAI</code>, or <code>CUSTOM</code>).</li><li>Enter the API key (stored securely in IntelliJ&#39;s <code>PasswordSafe</code>), base URL (auto-filled for known providers), and model name.</li><li>Click <strong>Test Connection</strong> to verify. The test uses the on-screen field values, so you can verify before clicking Apply/OK.</li><li>Click <strong>Auto-detect</strong> to let EasyYapi infer the provider from environment variables (<code>OPENAI_API_KEY</code>, <code>ANTHROPIC_API_KEY</code>, <code>OLLAMA_HOST</code>, …).</li></ol><h3 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h3><ol><li>Open <strong>Settings → EasyApi → Rules</strong>.</li><li>Click <strong>Chat</strong> (bottom action bar) to reveal the inline AI panel, or <strong>Magic</strong> to run a built-in review-and-detect instruction.</li><li>Type a request in natural language. Examples: <ul><li>&quot;Rename all endpoints in <code>UserController</code> to start with <code>fetch_</code>.&quot;</li><li>&quot;Add the tag <code>internal</code> to all classes in the <code>internal</code> package.&quot;</li><li>&quot;Detect custom filters that require a header and add the rule for me.&quot;</li></ul></li><li>The assistant reads your existing rules, reasons about the request, and proposes rule content.</li><li>Review the proposal card. You can <strong>Edit</strong> the content before saving.</li><li>Click <strong>Save…</strong> — choose Global (<code>~/.easyapi/</code>) or Project (<code>&lt;project&gt;/.easyapi/</code>) scope + filename.</li><li>The rule file is written into the chosen folder and the config is reloaded immediately.</li></ol><p>The assistant <strong>never writes files without your explicit approval</strong> — every state-changing action tool requires an Approve click.</p><h3 id="the-magic-button" tabindex="-1">The Magic button <a class="header-anchor" href="#the-magic-button" aria-label="Permalink to &quot;The Magic button&quot;">​</a></h3><p><strong>Magic</strong> runs a built-in instruction that:</p><ol><li>Reviews your existing rules for gaps.</li><li>Scans the project for custom framework patterns that lack a rule (Filters, Interceptors, <code>ResponseBodyAdvice</code>, <code>HandlerMethodArgumentResolver</code>, meta-annotations).</li><li>Proposes a rule for each detection, following the <a href="https://github.com/tangcent/easy-yapi/blob/master/docs/knowledge-base/rule-guide.md#custom-pattern-catalog" target="_blank" rel="noreferrer">Custom-Pattern Catalog</a>.</li></ol><hr><h2 id="external-easy-yapi-assistant-skill" tabindex="-1">External <code>easy-yapi-assistant</code> skill <a class="header-anchor" href="#external-easy-yapi-assistant-skill" aria-label="Permalink to &quot;External \`easy-yapi-assistant\` skill&quot;">​</a></h2><p>For teams that drive rule authoring from an external AI tool (CLI agent, IDE assistant, CI helper), EasyYapi bundles the <code>easy-yapi-assistant</code> skill. The skill ships inside the plugin and exposes the same knowledge base the in-IDE assistant uses, so external tools and the built-in assistant always author rules from the same source of truth.</p><p>The skill exposes:</p><ul><li><strong>Rule-key catalog</strong> — the canonical list of supported rule keys.</li><li><strong>Custom-Pattern Catalog</strong> — the same patterns the Magic button detects.</li><li><strong>Helper scripts</strong> — <code>list_rule_files.sh</code>, <code>read_rule_file.sh</code>, <code>get_existing_rules_for_key.sh</code> for inspecting existing rules in <code>.easyapi/</code> folders.</li></ul><p>Use the external skill when you want to:</p><ul><li>Author rules from a terminal-based AI tool.</li><li>Batch-detect custom framework behaviour across multiple repos in CI.</li><li>Generate rule stubs that a human reviewer finalises inside the IDE.</li></ul><hr><h2 id="what-s-new-in-3-1-x" tabindex="-1">What&#39;s new in 3.1.x <a class="header-anchor" href="#what-s-new-in-3-1-x" aria-label="Permalink to &quot;What&#39;s new in 3.1.x&quot;">​</a></h2><p>A few recent changes worth knowing about:</p><ul><li><strong>Folder-based rule management</strong> (<code>#1398</code>) — <code>.easyapi/*.rules</code> folder model at project and global scopes, replacing the legacy single-file workflow. Legacy <code>.easy.api.config*</code> files are still read for backwards compatibility.</li><li><strong>Built-in AI Assistant</strong> (<code>#1398</code>) — provider-neutral AI service (LangChain4j-backed) with a rule-authoring agent embedded in the Rules tab. Dedicated AI settings tab promoted to top level.</li><li><strong>Postman environment sync</strong> (<code>#722</code>) — sync Postman environments to the API Dashboard with inline editing in the endpoint details panel.</li><li><strong>Logging discipline</strong> (<code>#1393</code>, <code>#1394</code>, <code>#1396</code>) — the EasyAPI console defaults to <code>SILENT</code> and is hidden when the log level is <code>SILENT</code>. When the plugin fails, it now surfaces a self-explanatory notification instead of a silent stack trace.</li><li><strong>AI key storage</strong> (<code>#1403</code>) — AI provider keys are stored in IntelliJ&#39;s <code>PasswordSafe</code> via a dedicated <code>AiApiKeyStore</code>, no longer in plain settings.</li></ul><p>For the full release notes, see the <a href="https://github.com/tangcent/easy-yapi/blob/master/CHANGELOG.md" target="_blank" rel="noreferrer">changelog</a>.</p>`,43)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
